select

from biz_maintain_package_order a inner join biz_maintain_package b on a.packageid = b.id left join biz_maintain_order_pushrecord c on a.id = c.maintain_order_id
left join sys_user d on c.account = d.account


        and (b.package_name like CONCAT('%',#{condition},'%') or a.phone like CONCAT('%',#{condition},'%'))


        and (a.create_time between CONCAT(#{order.createStartTime},' 00:00:00') and CONCAT(#{order.createEndTime},' 23:59:59'))


        and a.order_status = #{order.orderStatus}


        and a.openid = #{order.openid}


        and c.account = #{order.account}


        and b.package_type = #{order.packageType}


ORDER BY createTime desc

